import { create } from 'zustand'

interface AppState {
  loading: boolean
  theme: 'light' | 'dark'
  toggleTheme: () => void
  setLoading: (loading: boolean) => void
}

export const useAppStore = create<AppState>((set) => ({
  loading: false,
  theme: 'light',
  toggleTheme: () => set((state) => ({ theme: state.theme === 'light' ? 'dark' : 'light' })),
  setLoading: (loading: boolean) => set({ loading })
}))
